proof fn phi_2_lemma_view_addr_aligned_directory_below_max(pde: PDE)
    requires
        pde.layer@ < 4,
        pde@ is Directory,
    ensures
        pde@->Directory_addr < usize::MAX - 4096,
        aligned(pde@->Directory_addr as nat, 4096),
{
    pde.lemma_view_addr_aligned();
}

proof fn phi_3_write_seq_preserves_pml4_chained(mem: PTMem, w1: Seq<(usize, usize)>, w2: Seq<(usize, usize)>)
    ensures
        mem.write_seq(w1).write_seq(w2).pml4 == mem.pml4,
{
    mem.lemma_write_seq(w1);
    mem.write_seq(w1).lemma_write_seq(w2);
}

proof fn phi_4_lemma_view_addr_aligned_page_addr_8_aligned(pde: PDE)
    requires
        pde.layer@ < 4,
        pde@ is Page,
    ensures
        aligned(pde@->Page_addr as nat, 8),
        pde@->Page_addr < usize::MAX - 4096,
{
    pde.lemma_view_addr_aligned();
}

proof fn phi_5_bit_indices_less_512_implies_walk_addr_bounded(mem: PTMem, va: usize)
    requires
        mem.pml4 < usize::MAX - 4096,
    ensures
        add(mem.pml4, mul(l0_bits!(va), WORD_SIZE)) < mem.pml4 + 4096,
{
    lemma_bit_indices_less_512(va);
    assert(l0_bits!(va) < 512);
    assert(mul(l0_bits!(va), WORD_SIZE) < 4096) by {
        assert(forall|x: usize| x < 512 ==> mul(x, 8usize) < 4096) by (bit_vector);
    };
}
